# Shapes module - base geometry classes

@abstract
class Shape:
    name: str

    def __init__(self, shape_name: str):
        self.name = shape_name

    @abstract
    def area(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

class Circle(Shape):
    radius: float

    def __init__(self, r: float):
        super().__init__("Circle")
        self.radius = r

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"{self.name} with radius {self.radius}"

