# Container module - manages collections of shapes
from shapes import Shape

class ShapeContainer:
    count: int
    total_area: float

    def __init__(self):
        self.count = 0
        self.total_area = 0.0

    def add_shape(self, shape: Shape) -> None:
        self.count += 1
        self.total_area += shape.area()

    def get_average_area(self) -> float:
        if self.count == 0:
            return 0.0
        return self.total_area / float(self.count)
